module j_module (
    input [1:0] u,
    output reg obf_g
);

    always @(*) begin
        case (u)
            2'b00: obf_g = 0;
            2'b01: obf_g = 1;
            2'b10: obf_g = 0;
            2'b11: obf_g = 1;
            default: obf_g = 0; // Default case
        endcase
    end
endmodule
